use std::collections::HashMap;

fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    let n = n as usize;
    let mut graph: HashMap<usize, Vec<(usize, i64)>> = HashMap::new();

    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let w = edge[2];
        graph.entry(u).or_insert_with(Vec::new).push((v, w));
        graph.entry(v).or_insert_with(Vec::new).push((u, w));
    }

    let mut parent = vec![0; n];
    let mut rank = vec![1; n];

    for i in 0..n {
        parent[i] = i;
    }

    fn find(parent: &Vec<usize>, x: usize) -> usize {
        if parent[x] != x {
            parent[x] = find(parent, parent[x]);
        }
        parent[x]
    }

    fn union(parent: &mut Vec<usize>, rank: &mut Vec<usize>, x: usize, y: usize) -> bool {
        let x_root = find(parent, x);
        let y_root = find(parent, y);

        if x_root == y_root {
            return false;
        }

        if rank[x_root] < rank[y_root] {
            parent[x_root] = y_root;
        } else {
            parent[y_root] = x_root;
            if rank[x_root] == rank[y_root] {
                rank[x_root] += 1;
            }
        }
        true
    }

    let mut edges_sorted: Vec<(i64, usize, usize)> = edges.iter()
        .map(|e| (e[2], e[0] as usize, e[1] as usize))
        .collect();

    edges_sorted.sort_by(|a, b| b.0.cmp(&a.0));

    let mut components = 0;
    let mut max_cost = 0;
    let mut max_edges = HashMap::new();

    for edge in &edges_sorted {
        let (w, u, v) = (*edge);
        let u_root = find(&parent, u);
        let v_root = find(&parent, v);

        if u_root != v_root {
            components += 1;
            union(&mut parent, &mut rank, u, v);
            let current_max = max_edges.entry(u_root).or_insert(0);
            *current_max = std::cmp::max(*current_max, w);
            let current_max_v = max_edges.entry(v_root).or_insert(0);
            *current_max_v = std::cmp::max(*current_max_v, w);
        }

        if components == k {
            break;
        }
    }

    let mut result = 0;
    for &cost in max_edges.values() {
        result = std::cmp::max(result, cost);
    }

    result
